// RateLimitRetryDefaultBudget is the default total wait budget for a retrying
// bead or attempt.
const RateLimitRetryDefaultBudget = 5 * time.Minute

// RateLimitRetryDefaultPerWaitCap caps any single retry wait so a misbehaving
// provider cannot pin the caller with an arbitrarily long Retry-After.
const RateLimitRetryDefaultPerWaitCap = 60 * time.Second

// RateLimitBudgetExhaustedReason is the canonical reason string used when the
// retry budget is exhausted.
const RateLimitBudgetExhaustedReason = "rate-limited beyond budget"

var rateLimitBackoffSchedule = []time.Duration{
	1 * time.Second,
	5 * time.Second,
	15 * time.Second,
	30 * time.Second,
	60 * time.Second,
}

// RateLimitWaitDecision captures the outcome of one rate-limit evaluation.
type RateLimitWaitDecision struct {
	ShouldRetry bool
	Wait        time.Duration
	Source      string
	Reason      string
}

// RateLimitRetryConfig carries the shared retry policy knobs.
type RateLimitRetryConfig struct {
	Budget     time.Duration
	PerWaitCap time.Duration
	Evaluator  func(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision
	Sleep      func(ctx context.Context, d time.Duration) error
	Now        func() time.Time
}

// RateLimitRetryInfo captures the shared telemetry fields for a retry event.
type RateLimitRetryInfo struct {
	Attempt    int
	Wait       time.Duration
	Source     string
	Elapsed    time.Duration
	OverBudget bool
}

// EvaluateRateLimitWait decides whether to retry and how long to wait.
func EvaluateRateLimitWait(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision {
	if budget > 0 && elapsed >= budget {
		return RateLimitWaitDecision{
			ShouldRetry: false,
			Reason:      RateLimitBudgetExhaustedReason,
		}
	}

	var wait time.Duration
	var source string
	if retryAfter > 0 {
		wait = retryAfter
		source = "retry-after"
	} else {
		idx := attempt - 1
		if idx < 0 {
			idx = 0
		}
		if idx >= len(rateLimitBackoffSchedule) {
			idx = len(rateLimitBackoffSchedule) - 1
		}
		wait = rateLimitBackoffSchedule[idx]
		source = "exponential-backoff"
	}

	if perWaitCap > 0 && wait > perWaitCap {
		wait = perWaitCap
	}

	if budget > 0 && elapsed+wait > budget {
		remaining := budget - elapsed
		if remaining <= 0 {
			return RateLimitWaitDecision{
				ShouldRetry: false,
				Reason:      RateLimitBudgetExhaustedReason,
			}
		}
		wait = remaining
	}

	return RateLimitWaitDecision{
		ShouldRetry: true,
		Wait:        wait,
		Source:      source,
	}
}

// IsRateLimitText reports whether the combined error/stderr/detail text
// indicates a rate-limit condition.
func IsRateLimitText(combined string) bool {
	if combined == "" {
		return false
	}
	lower := strings.ToLower(combined)
	if strings.Contains(lower, "quota exceeded") ||
		strings.Contains(lower, "insufficient quota") ||
		strings.Contains(lower, "no viable provider") {
		return false
	}
	if strings.Contains(lower, "rate limit") || strings.Contains(lower, "ratelimit") {
		return true
	}
	return hasIsolated429(lower)
}

func hasIsolated429(s string) bool {
	for i := 0; i+3 <= len(s); i++ {
		if s[i:i+3] != "429" {
			continue
		}
		if i > 0 {
			c := s[i-1]
			if c >= '0' && c <= '9' {
				continue
			}
		}
		if i+3 < len(s) {
			c := s[i+3]
			if c >= '0' && c <= '9' {
				continue
			}
		}
		return true
	}
	return false
}

// ParseRetryAfter parses a Retry-After value as seconds, an HTTP-date, or a
// Go duration literal.
func ParseRetryAfter(value string, now time.Time) time.Duration {
	value = strings.TrimSpace(value)
	if value == "" {
		return 0
	}
	if secs, err := strconv.Atoi(value); err == nil {
		if secs < 0 {
			return 0
		}
		return time.Duration(secs) * time.Second
	}
	if t, err := http.ParseTime(value); err == nil {
		d := t.Sub(now)
		if d < 0 {
			return 0
		}
		return d
	}
	if d, err := time.ParseDuration(value); err == nil && d >= 0 {
		return d
	}
	return 0
}

// ExtractRetryAfterFromStderr scans stderr for a Retry-After hint.
func ExtractRetryAfterFromStderr(stderr string, now time.Time) time.Duration {
	if stderr == "" {
		return 0
	}
	lower := strings.ToLower(stderr)
	for _, marker := range []string{"retry-after:", "retry_after=", "retry-after ", "retry after "} {
		idx := strings.Index(lower, marker)
		if idx < 0 {
			continue
		}
		rest := stderr[idx+len(marker):]
		if eol := strings.IndexAny(rest, "\r\n"); eol >= 0 {
			rest = rest[:eol]
		}
		rest = strings.TrimSpace(rest)
		rest = strings.Trim(rest, "\"',")
		if d := ParseRetryAfter(rest, now); d > 0 {
			return d
		}
	}
	return 0
}

