 19	// RateLimitBudgetExhaustedReason is the canonical reason string used when the
 20	// retry budget is exhausted.
 21	const RateLimitBudgetExhaustedReason = "rate-limited beyond budget"
 22	
 23	var rateLimitBackoffSchedule = []time.Duration{
 24		1 * time.Second,
 25		5 * time.Second,
 26		15 * time.Second,
 27		30 * time.Second,
 28		60 * time.Second,
 29	}
