 57	// EvaluateRateLimitWait decides whether to retry and how long to wait.
 58	func EvaluateRateLimitWait(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision {
 59		if budget > 0 && elapsed >= budget {
 60			return RateLimitWaitDecision{
 61				ShouldRetry: false,
 62				Reason:      RateLimitBudgetExhaustedReason,
 63			}
 64		}
 65	
 66		var wait time.Duration
 67		var source string
 68		if retryAfter > 0 {
 69			wait = retryAfter
 70			source = "retry-after"
 71		} else {
 72			idx := attempt - 1
 73			if idx < 0 {
 74				idx = 0
 75			}
 76			if idx >= len(rateLimitBackoffSchedule) {
 77				idx = len(rateLimitBackoffSchedule) - 1
 78			}
 79			wait = rateLimitBackoffSchedule[idx]
 80			source = "exponential-backoff"
 81		}
 82	
 83		if perWaitCap > 0 && wait > perWaitCap {
 84			wait = perWaitCap
 85		}
 86	
 87		if budget > 0 && elapsed+wait > budget {
 88			remaining := budget - elapsed
 89			if remaining <= 0 {
 90				return RateLimitWaitDecision{
 91					ShouldRetry: false,
 92					Reason:      RateLimitBudgetExhaustedReason,
 93				}
 94			}
 95			wait = remaining
 96		}
 97	
 98		return RateLimitWaitDecision{
 99			ShouldRetry: true,
100			Wait:        wait,
101			Source:      source,
102		}
103	}
