105	// IsRateLimitText reports whether the combined error/stderr/detail text
106	// indicates a rate-limit condition.
107	func IsRateLimitText(combined string) bool {
108		if combined == "" {
109			return false
110		}
111		lower := strings.ToLower(combined)
112		if strings.Contains(lower, "quota exceeded") ||
113			strings.Contains(lower, "insufficient quota") ||
114			strings.Contains(lower, "no viable provider") {
115			return false
116		}
117		if strings.Contains(lower, "rate limit") || strings.Contains(lower, "ratelimit") {
118			return true
119		}
120		return hasIsolated429(lower)
121	}
122	
123	func hasIsolated429(s string) bool {
124		for i := 0; i+3 <= len(s); i++ {
125			if s[i:i+3] != "429" {
126				continue
127			}
128			if i > 0 {
129				c := s[i-1]
130				if c >= '0' && c <= '9' {
131					continue
132				}
133			}
134			if i+3 < len(s) {
135				c := s[i+3]
136				if c >= '0' && c <= '9' {
137					continue
138				}
139			}
140			return true
141		}
142		return false
143	}
144	
145	// ParseRetryAfter parses a Retry-After value as seconds, an HTTP-date, or a
146	// Go duration literal.
147	func ParseRetryAfter(value string, now time.Time) time.Duration {
148		value = strings.TrimSpace(value)
149		if value == "" {
150			return 0
151		}
152		if secs, err := strconv.Atoi(value); err == nil {
153			if secs < 0 {
154				return 0
155			}
156			return time.Duration(secs) * time.Second
157		}
158		if t, err := http.ParseTime(value); err == nil {
159			d := t.Sub(now)
160			if d < 0 {
161				return 0
162			}
163			return d
164		}
165		if d, err := time.ParseDuration(value); err == nil && d >= 0 {
166			return d
167		}
168		return 0
169	}
170	
171	// ExtractRetryAfterFromStderr scans stderr for a Retry-After hint.
172	func ExtractRetryAfterFromStderr(stderr string, now time.Time) time.Duration {
173		if stderr == "" {
174			return 0
175		}
176		lower := strings.ToLower(stderr)
177		for _, marker := range []string{"retry-after:", "retry_after=", "retry-after ", "retry after "} {
178			idx := strings.Index(lower, marker)
179			if idx < 0 {
180				continue
181			}
182			rest := stderr[idx+len(marker):]
183			if eol := strings.IndexAny(rest, "\r\n"); eol >= 0 {
184				rest = rest[:eol]
185			}
186			rest = strings.TrimSpace(rest)
187			rest = strings.Trim(rest, "\"',")
188			if d := ParseRetryAfter(rest, now); d > 0 {
189				return d
190			}
191		}
192		return 0
193	}

430		RateLimitBudgetExhaustedReason  = ratelimitpolicy.RateLimitBudgetExhaustedReason
431	)
