441	func resolveRateLimitRetryConfig(opts AttemptOpts) RateLimitRetryConfig {
442		cfg := RateLimitRetryConfig{
443			RateLimitRetryConfig: ratelimitpolicy.RateLimitRetryConfig{
444				Budget:     opts.RateLimitBudget,
445				PerWaitCap: opts.RateLimitPerWaitCap,
446				Evaluator:  opts.RateLimitWaitEvaluator,
447				Sleep:      opts.RateLimitSleep,
448				Now:        opts.RateLimitNow,
449			},
450			OnRetry: opts.RateLimitOnRetry,
451		}
452		if cfg.Budget == 0 {
453			cfg.Budget = RateLimitRetryDefaultBudget
454		}
455		if cfg.PerWaitCap == 0 {
456			cfg.PerWaitCap = RateLimitRetryDefaultPerWaitCap
457		}
458		if cfg.Sleep == nil {
459			cfg.Sleep = ctxSleep
460		}
461		if cfg.Now == nil {
462			cfg.Now = time.Now
463		}
464		if cfg.Evaluator == nil {
465			cfg.Evaluator = ratelimitpolicy.EvaluateRateLimitWait
466		}
467		return cfg
468	}
469	
470	func ctxSleep(ctx context.Context, d time.Duration) error {
471		if d <= 0 {
472			return nil
473		}
474		t := time.NewTimer(d)
475		defer t.Stop()
476		select {
477		case <-ctx.Done():
478			return ctx.Err()
479		case <-t.C:
480			return nil
481		}
482	}
483	
484	func evaluateRateLimitAttempt(report Report, cfg RateLimitRetryConfig, attempt int, elapsed, budget time.Duration) (RateLimitWaitDecision, time.Duration) {
485		if cfg.Budget < 0 || budget < 0 {
486			return RateLimitWaitDecision{ShouldRetry: false}, 0
487		}
488		if !IsRateLimitReport(&report) {
489			return RateLimitWaitDecision{ShouldRetry: false}, 0
490		}
491	
492		retryAfter := ratelimitpolicy.ExtractRetryAfterFromStderr(report.Stderr, cfg.Now())
493		decision := cfg.Evaluator(retryAfter, attempt, elapsed, budget, cfg.PerWaitCap)
494		if !decision.ShouldRetry {
495			decision.Reason = RateLimitBudgetExhaustedReason
496		}
497		return decision, retryAfter
498	}
499	
500	func IsRateLimitReport(report *Report) bool {
501		if report == nil {
502			return false
503		}
504		combined := strings.ToLower(report.Error + "\n" + report.Stderr + "\n" + report.Detail)
505		return ratelimitpolicy.IsRateLimitText(combined)
506	}
507	
508	func ShouldAttemptConflictRecovery(report Report, projectRoot string) bool {
509		if report.PreserveRef == "" || projectRoot == "" {
510			return false
511		}
512		switch report.Status {
513		case StatusLandConflict:
514			return true
515		case StatusExecutionFailed:
516			return report.BaseRev != "" && report.ResultRev != "" && report.ResultRev != report.BaseRev
517		}
518		return false
519	}
